def download_url(url: str, dst_path: str, overwrite: bool = False, timeout: int = 60) -> str:
    os.makedirs(os.path.dirname(os.path.abspath(dst_path)), exist_ok=True)
    if os.path.exists(dst_path) and not overwrite:
        return dst_path

