def main():
    cfg = parse_args()
    set_seed(cfg.seed)

    device = torch.device(cfg.device)
    model = build_model(cfg.model_name, cfg.num_classes, cfg.pretrained_backbone)

    if cfg.ckpt_url:
        ckpt_obj = load_checkpoint_from_url_torchload(
            cfg.ckpt_url,
            map_location="cpu",
            cache_dir=cfg.cache_dir,
            filename=cfg.ckpt_filename,
            overwrite=cfg.overwrite_ckpt,
        )
        info = load_weights_into_model(model, ckpt_obj, strict=cfg.strict_load)
        sys.stderr.write(json.dumps({"checkpoint_load": info}, indent=2) + "\n")

    if cfg.freeze:
        freeze_backbone(model)
        adapt_classifier(model, cfg.num_classes)
        for p in model.parameters():
            if p.requires_grad:
                pass

    model.to(device)

    train_loader, val_loader = make_dataloaders(
        cfg.data_dir, cfg.image_size, cfg.batch_size, cfg.num_workers, cfg.val_split, cfg.seed
    )

    criterion = nn.CrossEntropyLoss()

    trainable_params = [p for p in model.parameters() if p.requires_grad]
    if len(trainable_params) == 0:
        raise RuntimeError("No trainable parameters. Disable --freeze or ensure classifier is trainable.")

    if cfg.model_name.lower().startswith("resnet"):
        optimizer = optim.SGD(trainable_params, lr=cfg.lr, momentum=cfg.momentum, weight_decay=cfg.weight_decay)
    else:
        optimizer = optim.AdamW(trainable_params, lr=cfg.lr, weight_decay=cfg.weight_decay)

    scaler = torch.cuda.amp.GradScaler() if (cfg.amp and device.type == "cuda") else None

    best_val_acc = -1.0
    out_dir = os.path.join(cfg.cache_dir, "finetuned")
    os.makedirs(out_dir, exist_ok=True)
    run_tag = f"{cfg.model_name}_cls{cfg.num_classes}_{int(time.time())}"
    best_path = os.path.join(out_dir, f"{run_tag}_best.pt")
    last_path = os.path.join(out_dir, f"{run_tag}_last.pt")

    for epoch in range(1, cfg.epochs + 1):
        tr = train_one_epoch(model, train_loader, criterion, optimizer, str(device), scaler=scaler)
        va = evaluate(model, val_loader, criterion, str(device))

        improved = va["acc"] > best_val_acc
        if improved:
            best_val_acc = va["acc"]
            save_checkpoint(best_path, model, optimizer, epoch, best_val_acc, extra={"train": tr, "val": va, "config": cfg.__dict__})

        save_checkpoint(last_path, model, optimizer, epoch, best_val_acc, extra={"train": tr, "val": va, "config": cfg.__dict__})

        sys.stdout.write(json.dumps({
            "epoch": epoch,
            "train_loss": tr["loss"],
            "train_acc": tr["acc"],
            "val_loss": va["loss"],
            "val_acc": va["acc"],
            "best_val_acc": best_val_acc,
            "saved_best": bool(improved),
            "best_path": best_path if improved else None,
            "last_path": last_path,
        }) + "\n")
